// Collect all inputs
const agentData = $('Get Agent Status').first().json;
const proData = $('Get CLI Pro Status').first().json;
const cliHealth = $('Get CLI Worker Health').first().json;

const workers = agentData.workers || [];
const issues = [];
const insights = [];
const now = Date.now() / 1000;

// ── Check each agent ────────────────────────────────────────────────────
for (const w of workers) {
  if (w.state === 'strike') {
    issues.push(`${w.id} on STRIKE (${w.task || 'no credits'})`);
  } else if (w.state === 'sick') {
    issues.push(`${w.id} is SICK — needs attention`);
  } else if (w.state === 'idle' && w.last_worked_ago !== null && w.last_worked_ago > 3600) {
    insights.push(`${w.id} idle for ${Math.round(w.last_worked_ago/60)}min`);
  } else if (w.last_worked === 0 && !['Gemini CLI','DeepSeek','Shell Agent','GitHub Agent'].includes(w.id)) {
    insights.push(`${w.id} has NEVER been active`);
  }
}

// ── Check Claude CLI Pro ────────────────────────────────────────────────
const proAvailable = proData.pro_available;
const proMode = proData.mode || '';
const cliDown = proData.cli_down || false;

if (cliDown) {
  issues.push(`Claude CLI Pro is DOWN (mode: ${proMode})`);
} else if (proAvailable === false) {
  issues.push(`Claude CLI Pro UNAVAILABLE — ${proMode}`);
} else if (proAvailable === true) {
  insights.push(`Claude CLI Pro: OK (mode: ${proMode})`);
}

// ── Check CLI worker ────────────────────────────────────────────────────
const cliWorkerOk = cliHealth.status === 'ok';
const claudeAvail = cliHealth.claude_available;
const geminiAvail = cliHealth.gemini_available;

if (!cliWorkerOk) {
  issues.push(`CLI Worker (inspiring-cat) DEGRADED — claude=${claudeAvail} gemini=${geminiAvail}`);
} else {
  if (!claudeAvail) issues.push('CLI Worker: Claude binary unavailable');
  if (!geminiAvail) insights.push('Gemini CLI: not available on worker');
}

// ── Gemini on dashboard ─────────────────────────────────────────────────
const geminiWorker = workers.find(w => w.id === 'Gemini CLI');
if (geminiWorker && geminiWorker.state === 'sleeping' && !proData.gemini_available) {
  insights.push('Gemini CLI: not configured (no GEMINI_SESSION_TOKEN)');
}

// ── Strike count ────────────────────────────────────────────────────────
const onStrike = workers.filter(w => w.state === 'strike').length;
const apiAvailable = proData.api_available;
if (onStrike >= 2 && apiAvailable === false) {
  issues.push(`ALL Anthropic API agents on strike — ANTHROPIC_API_KEY has no credits`);
}

// ── Build report ────────────────────────────────────────────────────────
const hasIssues = issues.length > 0;
const status = hasIssues ? '⚠️ ISSUES DETECTED' : '✅ ALL SYSTEMS OK';

const lines = [
  `${status} | ${new Date().toISOString()}`,
  ...issues.map(i => `  ❌ ${i}`),
  ...insights.map(i => `  ℹ️  ${i}`),
  `  Workers: ${workers.filter(w=>w.state==='idle'||w.state==='working').length} active, ${onStrike} on strike, ${workers.filter(w=>w.state==='sick').length} sick`,
];

const message = lines.join(' | ');

return [{ json: { message, hasIssues, issueCount: issues.length, issues, insights, status } }];
